        "function test(N,r)\n",
        "    return 1.0/(1.0+r/N)^N\n",
        "end\n",
        "\n",
        "test(10000,.01) ≈ exp(-.01)\n",
        "\n",
        "#Example European Call Option\n",
        "underlying = 100\n",
        "strike = 100\n",
        "days=125\n",
        "tradingDayYear=255\n",
        "ttm = days/tradingDayYear\n",
        "rf = 0.05\n",
        "ivol = 0.2"
